export default function SettingsModal({
  settingsOpen,
  onClose,
  handleSubmit,
  showUserMessages,
  setShowUserMessages,
  showSidebar,
  setShowSidebar,
  showSendButton,
  setShowSendButton,
  setConversations,
  setCurrentId,
}) {
  if (!settingsOpen) {
    return null;
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content" onClick={(e) => e.stopPropagation()}>
        <h1>Settings</h1>
        <div className="form-div">
          <form
            onSubmit={(e) => {
              e.preventDefault();
              handleSubmit();
            }}
          >
            <button
              onClick={() => {
                console.log("clicked");
                localStorage.clear();
                setConversations({});
                setCurrentId(null);
              }}
              class
            >
              DELETE
            </button>
            <label>
              User Messages:
              <input
                type="checkbox"
                name="usermessages"
                checked={showUserMessages}
                onChange={(e) => setShowUserMessages(e.target.checked)}
              />
            </label>
            <label>
              Sidebar:
              <input
                type="checkbox"
                name="sidebar"
                checked={showSidebar}
                onChange={(e) => setShowSidebar(e.target.checked)}
              />
            </label>
            <label>
              Send Button:
              <input
                type="checkbox"
                name="sendbutton"
                checked={showSendButton}
                onChange={(e) => setShowSendButton(e.target.checked)}
              />
            </label>
            <button type="submit" className="modal-button">
              Save
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
